"use strict";

// src-electron/electron-preload.ts
var import_electron = require("electron");

// src-electron/preload/scripts/simplevmdetect.js
var canvas = document.createElement("canvas");
var gl = canvas.getContext("webgl");
var virtual = false;
if (gl) {
  const debugInfo = gl.getExtension("WEBGL_debug_renderer_info");
  if (debugInfo) {
    const vendor = gl.getParameter(debugInfo.UNMASKED_VENDOR_WEBGL).toLowerCase();
    const renderer = gl.getParameter(debugInfo.UNMASKED_RENDERER_WEBGL).toLowerCase();
    const keywords = [
      "vmware",
      "virtualbox",
      "parallels",
      "solarwinds",
      "qemu",
      "hyper-v",
      "bootcamp",
      "xen",
      "citrix",
      "kvm",
      "wsl",
      "docker",
      "cloud",
      "llvmpipe",
      "microsoft basic render driver",
      "basic render",
      "virgl",
      "virtio",
      "spice",
      "qxl"
    ];
    const isLowEndGraphics = renderer.includes("swiftshader") || renderer.includes("llvmpipe") || renderer.includes("basic render");
    let matchFound = false;
    keywords.forEach((keyword) => {
      if (vendor.includes(keyword) || renderer.includes(keyword)) {
        matchFound = true;
        virtual = true;
      }
    });
    if (isLowEndGraphics) {
      virtual = true;
    }
    const isWayland = typeof process !== "undefined" && process.env.WAYLAND_DISPLAY;
    if (isWayland && renderer.includes("swiftshader")) {
      if (!matchFound) {
        console.log("Wayland detected with SwiftShader, likely not a VM.");
        virtual = false;
      }
    }
  } else {
    console.log("WEBGL_debug_renderer_info nicht verf\xFCgbar.");
    virtual = true;
  }
} else {
  console.log("WebGL wird nicht unterst\xFCtzt, m\xF6glicherweise eine VM.");
  virtual = true;
}
var simplevmdetect_default = virtual;

// src-electron/electron-preload.ts
var config = import_electron.ipcRenderer.sendSync("getconfig");
var virtualCpu = import_electron.ipcRenderer.sendSync("get-cpu-info");
if (simplevmdetect_default || virtualCpu) {
  import_electron.ipcRenderer.send("virtualized");
}
import_electron.contextBridge.exposeInMainWorld("config", config);
import_electron.contextBridge.exposeInMainWorld("ipcRenderer", {
  send: (channel, data) => import_electron.ipcRenderer.send(channel, data),
  sendSync: (channel, data) => import_electron.ipcRenderer.sendSync(channel, data),
  on: (channel, func) => import_electron.ipcRenderer.on(channel, (event, ...args) => func(event, ...args)),
  invoke: (channel, ...data) => import_electron.ipcRenderer.invoke(channel, ...data),
  // Hier mit Spread-Operator
  removeListener: (channel, listener) => import_electron.ipcRenderer.removeListener(channel, listener),
  // Entfernt einen Listener
  removeAllListeners: (channel) => import_electron.ipcRenderer.removeAllListeners(channel)
  // Entfernt alle Listener für einen Channel
});
